# GraphQL Types

class ReviewSortEnum(graphene.Enum):
    NEWEST = "newest"
    OLDEST = "oldest"
    HIGHEST_RATED = "highest_rated"
    LOWEST_RATED = "lowest_rated"
    MOST_HELPFUL = "most_helpful"


class ProductSortEnum(graphene.Enum):
    NAME_ASC = "name_asc"
    NAME_DESC = "name_desc"
    PRICE_ASC = "price_asc"
    PRICE_DESC = "price_desc"
    NEWEST = "newest"
    RATING = "rating"


class PriceRangeInput(graphene.InputObjectType):
    min_price = graphene.Float(description="Minimum price filter")
    max_price = graphene.Float(description="Maximum price filter")


class ReviewType(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()
    verified_purchase = graphene.Boolean()
    helpful_count = graphene.Int()
    created_at = graphene.String()
    user = graphene.Field(lambda: UserType)
    product = graphene.Field(lambda: ProductType)

    def resolve_user(self, info):
        user_data = next((u for u in USERS if u["id"] == self["user_id"]), None)
        return user_data

    def resolve_product(self, info):
        product_data = next((p for p in PRODUCTS if p["id"] == self["product_id"]), None)
        return product_data


class ReviewConnection(graphene.ObjectType):
    items = graphene.List(ReviewType, required=True)
    total_count = graphene.Int(required=True)
    average_rating = graphene.Float()
    rating_distribution = graphene.List(graphene.Int, description="Count of reviews per star rating [1-star, 2-star, 3-star, 4-star, 5-star]")


class UserType(graphene.ObjectType):
    id = graphene.ID(required=True)
    username = graphene.String(required=True)
    email = graphene.String(required=True)
    display_name = graphene.String()
    reviews = graphene.List(ReviewType)
    review_count = graphene.Int()

    def resolve_reviews(self, info):
        return [r for r in REVIEWS if r["user_id"] == self["id"]]

    def resolve_review_count(self, info):
        return len([r for r in REVIEWS if r["user_id"] == self["id"]])


class CategoryType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    slug = graphene.String(required=True)
    parent_id = graphene.ID()
    parent = graphene.Field(lambda: CategoryType)
    subcategories = graphene.List(lambda: CategoryType)
    products = graphene.List(lambda: ProductType, active_only=graphene.Boolean(default_value=True))
    product_count = graphene.Int(active_only=graphene.Boolean(default_value=True))

    def resolve_parent(self, info):
        if self["parent_id"] is None:
            return None
        return next((c for c in CATEGORIES if c["id"] == self["parent_id"]), None)

    def resolve_subcategories(self, info):
        return [c for c in CATEGORIES if c["parent_id"] == self["id"]]

    def resolve_products(self, info, active_only=True):
        # Include products from this category and its subcategories
        category_ids = [self["id"]]
        subcategories = [c for c in CATEGORIES if c["parent_id"] == self["id"]]
        category_ids.extend([c["id"] for c in subcategories])

        products = [p for p in PRODUCTS if p["category_id"] in category_ids]
        if active_only:
            products = [p for p in products if p["is_active"]]
        return products

    def resolve_product_count(self, info, active_only=True):
        category_ids = [self["id"]]
        subcategories = [c for c in CATEGORIES if c["parent_id"] == self["id"]]
        category_ids.extend([c["id"] for c in subcategories])

        products = [p for p in PRODUCTS if p["category_id"] in category_ids]
        if active_only:
            products = [p for p in products if p["is_active"]]
        return len(products)


class ProductType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    sale_price = graphene.Float()
    effective_price = graphene.Float(description="The sale price if on sale, otherwise the regular price")
    discount_percentage = graphene.Float(description="Discount percentage if on sale")
    sku = graphene.String(required=True)
    category_id = graphene.ID(required=True)
    category = graphene.Field(CategoryType)
    stock_quantity = graphene.Int()
    in_stock = graphene.Boolean()
    is_active = graphene.Boolean()
    image_url = graphene.String()
    tags = graphene.List(graphene.String)
    weight = graphene.Float(description="Weight in kg")
    dimensions = graphene.String()
    created_at = graphene.String()
    updated_at = graphene.String()
    reviews = graphene.Field(
        ReviewConnection,
        sort_by=ReviewSortEnum(),
        rating_filter=graphene.Int(),
        verified_only=graphene.Boolean(default_value=False),
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
    )
    average_rating = graphene.Float()
    review_count = graphene.Int()

    def resolve_category(self, info):
        return next((c for c in CATEGORIES if c["id"] == self["category_id"]), None)

    def resolve_effective_price(self, info):
        if self.get("sale_price") is not None:
            return self["sale_price"]
        return self["price"]

    def resolve_discount_percentage(self, info):
        if self.get("sale_price") is not None and self["price"] > 0:
            return round(((self["price"] - self["sale_price"]) / self["price"]) * 100, 1)
        return None

    def resolve_in_stock(self, info):
        return self["stock_quantity"] > 0

    def resolve_reviews(self, info, sort_by=None, rating_filter=None, verified_only=False, limit=10, offset=0):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self["id"]]

        if rating_filter is not None:
            product_reviews = [r for r in product_reviews if r["rating"] == rating_filter]

        if verified_only:
            product_reviews = [r for r in product_reviews if r["verified_purchase"]]

        total_count = len(product_reviews)

        # Calculate average rating from all matching reviews (before pagination)
        avg_rating = None
        if total_count > 0:
            avg_rating = round(sum(r["rating"] for r in product_reviews) / total_count, 1)

        # Rating distribution
        all_product_reviews = [r for r in REVIEWS if r["product_id"] == self["id"]]
        rating_dist = [0, 0, 0, 0, 0]
        for r in all_product_reviews:
            rating_dist[r["rating"] - 1] += 1

        # Sort
        if sort_by == ReviewSortEnum.NEWEST.value:
            product_reviews.sort(key=lambda x: x["created_at"], reverse=True)
        elif sort_by == ReviewSortEnum.OLDEST.value:
            product_reviews.sort(key=lambda x: x["created_at"])
        elif sort_by == ReviewSortEnum.HIGHEST_RATED.value:
            product_reviews.sort(key=lambda x: x["rating"], reverse=True)
        elif sort_by == ReviewSortEnum.LOWEST_RATED.value:
            product_reviews.sort(key=lambda x: x["rating"])
        elif sort_by == ReviewSortEnum.MOST_HELPFUL.value:
            product_reviews.sort(key=lambda x: x["helpful_count"], reverse=True)
        else:
            product_reviews.sort(key=lambda x: x["created_at"], reverse=True)

        # Paginate
        paginated = product_reviews[offset:offset + limit]

        return ReviewConnection(
            items=paginated,
            total_count=total_count,
            average_rating=avg_rating,
            rating_distribution=rating_dist,
        )

    def resolve_average_rating(self, info):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self["id"]]
        if not product_reviews:
            return None
        return round(sum(r["rating"] for r in product_reviews) / len(product_reviews), 1)

    def resolve_review_count(self, info):
        return len([r for r in REVIEWS if r["product_id"] == self["id"]])


class ProductConnection(graphene.ObjectType):
    items = graphene.List(ProductType, required=True)
    total_count = graphene.Int(required=True)
    has_next_page = graphene.Boolean(required=True)
    has_previous_page = graphene.Boolean(required=True)


