# Mutations

class AddReview(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        user_id = graphene.ID(required=True)
        rating = graphene.Int(required=True)
        title = graphene.String(required=True)
        comment = graphene.String()
        verified_purchase = graphene.Boolean(default_value=False)

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, product_id, user_id, rating, title, comment=None, verified_purchase=False):
        # Validate product exists
        product = next((p for p in PRODUCTS if p["id"] == product_id), None)
        if not product:
            return AddReview(review=None, success=False, message="Product not found")

        # Validate user exists
        user = next((u for u in USERS if u["id"] == user_id), None)
        if not user:
            return AddReview(review=None, success=False, message="User not found")

        # Validate rating
        if rating < 1 or rating > 5:
            return AddReview(review=None, success=False, message="Rating must be between 1 and 5")

        # Check for duplicate review
        existing = next((r for r in REVIEWS if r["product_id"] == product_id and r["user_id"] == user_id), None)
        if existing:
            return AddReview(review=None, success=False, message="User has already reviewed this product")

        new_review = {
            "id": str(max(int(r["id"]) for r in REVIEWS) + 1),
            "product_id": product_id,
            "user_id": user_id,
            "rating": rating,
            "title": title,
            "comment": comment or "",
            "verified_purchase": verified_purchase,
            "helpful_count": 0,
            "created_at": datetime.utcnow().isoformat(),
        }
        REVIEWS.append(new_review)
        return AddReview(review=new_review, success=True, message="Review added successfully")


class MarkReviewHelpful(graphene.Mutation):
    class Arguments:
        review_id = graphene.ID(required=True)

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, review_id):
        review = next((r for r in REVIEWS if r["id"] == review_id), None)
        if not review:
            return MarkReviewHelpful(review=None, success=False, message="Review not found")

        review["helpful_count"] += 1
        return MarkReviewHelpful(review=review, success=True, message="Review marked as helpful")


class AddProduct(graphene.Mutation):
    class Arguments:
        name = graphene.String(required=True)
        description = graphene.String()
        price = graphene.Float(required=True)
        sale_price = graphene.Float()
        sku = graphene.String(required=True)
        category_id = graphene.ID(required=True)
        stock_quantity = graphene.Int(default_value=0)
        image_url = graphene.String()
        tags = graphene.List(graphene.String)
        weight = graphene.Float()
        dimensions = graphene.String()

    product = graphene.Field(ProductType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, name, price, sku, category_id, description=None, sale_price=None,
               stock_quantity=0, image_url=None, tags=None, weight=None, dimensions=None):
        # Validate category exists
        category = next((c for c in CATEGORIES if c["id"] == category_id), None)
        if not category:
            return AddProduct(product=None, success=False, message="Category not found")

        # Check SKU uniqueness
        existing = next((p for p in PRODUCTS if p["sku"] == sku), None)
        if existing:
            return AddProduct(product=None, success=False, message="SKU already exists")

        if price < 0:
            return AddProduct(product=None, success=False, message="Price must be non-negative")

        now = datetime.utcnow().isoformat()
        new_product = {
            "id": str(max(int(p["id"]) for p in PRODUCTS) + 1),
            "name": name,
            "description": description or "",
            "price": price,
            "sale_price": sale_price,
            "sku": sku,
            "category_id": category_id,
            "stock_quantity": stock_quantity,
            "is_active": True,
            "image_url": image_url,
            "tags": tags or [],
            "weight": weight,
            "dimensions": dimensions,
            "created_at": now,
            "updated_at": now,
        }
        PRODUCTS.append(new_product)
        return AddProduct(product=new_product, success=True, message="Product added successfully")


class UpdateProductStock(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        quantity = graphene.Int(required=True)

    product = graphene.Field(ProductType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, product_id, quantity):
        product = next((p for p in PRODUCTS if p["id"] == product_id), None)
        if not product:
            return UpdateProductStock(product=None, success=False, message="Product not found")

        if quantity < 0:
            return UpdateProductStock(product=None, success=False, message="Stock quantity cannot be negative")

        product["stock_quantity"] = quantity
        product["updated_at"] = datetime.utcnow().isoformat()
        return UpdateProductStock(product=product, success=True, message=f"Stock updated to {quantity}")


class Mutation(graphene.ObjectType):
    add_review = AddReview.Field(description="Add a new review for a product")
    mark_review_helpful = MarkReviewHelpful.Field(description="Mark a review as helpful")
    add_product = AddProduct.Field(description="Add a new product to the catalog")
    update_product_stock = UpdateProductStock.Field(description="Update product stock quantity")


# Query

class Query(graphene.ObjectType):
    # Product queries
    product = graphene.Field(
        ProductType,
        id=graphene.ID(),
        sku=graphene.String(),
        description="Get a single product by ID or SKU"
    )
    products = graphene.Field(
        ProductConnection,
        category_id=graphene.ID(),
        search=graphene.String(),
        tag=graphene.String(),
        price_range=PriceRangeInput(),
        active_only=graphene.Boolean(default_value=True),
        in_stock_only=graphene.Boolean(default_value=False),
        sort_by=ProductSortEnum(),
        limit=graphene.Int(default_value=20),
        offset=graphene.Int(default_value=0),
        description="Query products with filtering, sorting, and pagination"
    )
    featured_products = graphene.List(
        ProductType,
        limit=graphene.Int(default_value=5),
        description="Get featured products (on sale with highest discounts)"
    )

    # Category queries
    category = graphene.Field(
        CategoryType,
        id=graphene.ID(),
        slug=graphene.String(),
        description="Get a single category by ID or slug"
    )
    categories = graphene.List(
        CategoryType,
        root_only=graphene.Boolean(default_value=False),
        description="Get all categories, optionally only root categories"
    )

    # Review queries
    review = graphene.Field(
        ReviewType,
        id=graphene.ID(required=True),
        description="Get a single review by ID"
    )
    recent_reviews = graphene.List(
        ReviewType,
        limit=graphene.Int(default_value=10),
        description="Get most recent reviews across all products"
    )

    # User queries
    user = graphene.Field(
        UserType,
        id=graphene.ID(),
        username=graphene.String(),
        description="Get a user by ID or username"
    )

    # Stats
    catalog_stats = graphene.Field(
        CatalogStats,
        description="Get overall catalog statistics"
    )

    # Search
    search = graphene.List(
        ProductType,
        query=graphene.String(required=True),
        limit=graphene.Int(default_value=10),
        description="Search products by name, description, or tags"
    )

    def resolve_product(self, info, id=None, sku=None):
        if id:
            return next((p for p in PRODUCTS if p["id"] == id), None)
        if sku:
            return next((p for p in PRODUCTS if p["sku"] == sku), None)
        return None

    def resolve_products(self, info, category_id=None, search=None, tag=None,
                         price_range=None, active_only=True, in_stock_only=False,
                         sort_by=None, limit=20, offset=0):
        filtered = list(PRODUCTS)

        # Filter by active status
        if active_only:
            filtered = [p for p in filtered if p["is_active"]]

        # Filter by category (including subcategories)
        if category_id:
            category_ids = [category_id]
            subcategories = [c for c in CATEGORIES if c["parent_id"] == category_id]
            category_ids.extend([c["id"] for c in subcategories])
            filtered = [p for p in filtered if p["category_id"] in category_ids]

        # Search filter
        if search:
            search_lower = search.lower()
            filtered = [
                p for p in filtered
                if search_lower in p["name"].lower()
                or (p.get("description") and search_lower in p["description"].lower())
                or any(search_lower in tag.lower() for tag in p.get("tags", []))
            ]

        # Tag filter
        if tag:
            tag_lower = tag.lower()
            filtered = [p for p in filtered if tag_lower in [t.lower() for t in p.get("tags", [])]]

        # Price range filter
        if price_range:
            if price_range.min_price is not None:
                filtered = [p for p in filtered if (p.get("sale_price") or p["price"]) >= price_range.min_price]
            if price_range.max_price is not None:
                filtered = [p for p in filtered if (p.get("sale_price") or p["price"]) <= price_range.max_price]

        # In stock filter
        if in_stock_only:
            filtered = [p for p in filtered if p["stock_quantity"] > 0]

        total_count = len(filtered)

        # Sorting
        if sort_by == ProductSortEnum.NAME_ASC.value:
            filtered.sort(key=lambda x: x["name"].lower())
        elif sort_by == ProductSortEnum.NAME_DESC.value:
            filtered.sort(key=lambda x: x["name"].lower(), reverse=True)
        elif sort_by == ProductSortEnum.PRICE_ASC.value:
            filtered.sort(key=lambda x: x.get("sale_price") or x["price"])
        elif sort_by == ProductSortEnum.PRICE_DESC.value:
            filtered.sort(key=lambda x: x.get("sale_price") or x["price"], reverse=True)
        elif sort_by == ProductSortEnum.NEWEST.value:
            filtered.sort(key=lambda x: x["created_at"], reverse=True)
        elif sort_by == ProductSortEnum.RATING.value:
            def get_avg_rating(product):
                reviews = [r for r in REVIEWS if r["product_id"] == product["id"]]
                if not reviews:
                    return 0
                return sum(r["rating"] for r in reviews) / len(reviews)
            filtered.sort(key=get_avg_rating, reverse=True)

        # Pagination
        paginated = filtered[offset:offset + limit]

        return ProductConnection(
            items=paginated,
            total_count=total_count,
            has_next_page=(offset + limit) < total_count,
            has_previous_page=offset > 0,
        )

    def resolve_featured_products(self, info, limit=5):
        # Products on sale, sorted by discount percentage
        on_sale = [p for p in PRODUCTS if p.get("sale_price") is not None and p["is_active"]]
        on_sale.sort(
            key=lambda x: ((x["price"] - x["sale_price"]) / x["price"]) if x["price"] > 0 else 0,
            reverse=True
        )
        return on_sale[:limit]

    def resolve_category(self, info, id=None, slug=None):
        if id:
            return next((c for c in CATEGORIES if c["id"] == id), None)
        if slug:
            return next((c for c in CATEGORIES if c["slug"] == slug), None)
        return None

    def resolve_categories(self, info, root_only=False):
        if root_only:
            return [c for c in CATEGORIES if c["parent_id"] is None]
        return CATEGORIES

    def resolve_review(self, info, id):
        return next((r for r in REVIEWS if r["id"] == id), None)

    def resolve_recent_reviews(self, info, limit=10):
        sorted_reviews = sorted(REVIEWS, key=lambda x: x["created_at"], reverse=True)
        return sorted_reviews[:limit]

    def resolve_user(self, info, id=None, username=None):
        if id:
            return next((u for u in USERS if u["id"] == id), None)
        if username:
            return next((u for u in USERS if u["username"] == username), None)
        return None

    def resolve_catalog_stats(self, info):
        all_ratings = [r["rating"] for r in REVIEWS]
        avg_rating = round(sum(all_ratings) / len(all_ratings), 2) if all_ratings else None

        return CatalogStats(
            total_products=len(PRODUCTS),
            active_products=len([p for p in PRODUCTS if p["is_active"]]),
            total_categories=len(CATEGORIES),
            total_reviews=len(REVIEWS),
            average_product_rating=avg_rating,
            total_users=len(USERS),
        )

    def resolve_search(self, info, query, limit=10):
        query_lower = query.lower()
        results = []
        for p in PRODUCTS:
            if not p["is_active"]:
                continue
            score = 0
            # Exact name match gets highest score
            if query_lower == p["name"].lower():
                score = 100
            elif query_lower in p["name"].lower():
                score = 50
            if p.get("description") and query_lower in p["description"].lower():
                score += 20
            if any(query_lower in tag.lower() for tag in p.get("tags", [])):
                score += 30
            if query_lower in p.get("sku", "").lower():
                score += 40

            if score > 0:
                results.append((score, p))

        results.sort(key=lambda x: x[0], reverse=True)
        return [item[1] for item in results[:limit]]


# Create schema with introspection enabled for development/testing
# TODO: Disable introspection in production by setting introspection=False
schema = graphene.Schema(query=Query, mutation=Mutation)

# Flask application
app = Flask(__name__)

# GraphQL endpoint
app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True  # Enable GraphiQL interface for development
    )
)

